#!/bin/bash

# Script to compile the main book and individual chapters/appendices
# Author: Auto-generated
# Date: 2025-11-05

set -e  # Exit on error

echo "=========================================="
echo "Starting compilation of English version"
echo "=========================================="

# Create output directory for individual PDFs
mkdir -p build/individual_pdfs

# Function to compile a LaTeX file
compile_latex() {
    local file=$1
    local output_name=$2
    local dir=$(dirname "$file")
    
    echo ""
    echo "Compiling: $output_name"
    echo "------------------------------------------"
    
    cd "$dir"
    
    # First pass
    pdflatex -interaction=nonstopmode "$(basename $file)" > /dev/null 2>&1 || true
    
    # Run bibtex if .aux file exists
    if [ -f "${output_name}.aux" ]; then
        bibtex "${output_name}" > /dev/null 2>&1 || true
    fi
    
    # Second pass
    pdflatex -interaction=nonstopmode "$(basename $file)" > /dev/null 2>&1 || true
    
    # Third pass for references
    pdflatex -interaction=nonstopmode "$(basename $file)" > /dev/null 2>&1 || true
    
    cd - > /dev/null
    
    if [ -f "$dir/${output_name}.pdf" ]; then
        echo "✓ Successfully compiled: ${output_name}.pdf"
        return 0
    else
        echo "✗ Failed to compile: ${output_name}.pdf"
        return 1
    fi
}

# Step 1: Compile main book
echo ""
echo "=========================================="
echo "Step 1: Compiling main book (main.tex)"
echo "=========================================="

pdflatex -interaction=nonstopmode main.tex
bibtex main || true
makeindex main.idx || true
makeglossaries main || true
pdflatex -interaction=nonstopmode main.tex
pdflatex -interaction=nonstopmode main.tex

if [ -f "main.pdf" ]; then
    echo "✓ Main book compiled successfully: main.pdf"
else
    echo "✗ Failed to compile main book"
    exit 1
fi

# Step 2: Create standalone files for each chapter
echo ""
echo "=========================================="
echo "Step 2: Creating standalone chapter PDFs"
echo "=========================================="

# Array of chapters with chapter numbers
chapters=(
    "chapter01:1:Introduction to Sora2"
    "chapter02:2:Getting Started with Sora2"
    "chapter03:3:Mastering Prompt Engineering"
    "chapter04:4:Visual Storytelling Techniques"
    "chapter05:5:Advanced Creative Techniques"
    "chapter06:6:Technical Deep Dive"
    "chapter07:7:Commercial Applications"
    "chapter08:8:Workflow Integration"
    "chapter09:9:Ethics and Best Practices"
    "chapter10:10:Future Trends and Outlook"
    "chapter-sora2-vs-veo3-comparison:11:Sora 2 vs Veo 3 Comparison"
)

for chapter_info in "${chapters[@]}"; do
    IFS=':' read -r chapter_file chapter_num chapter_title <<< "$chapter_info"

