\\usepackage[T1]{fontenc}
\\usepackage{lmodern}
\\usepackage{geometry}
\\geometry{letterpaper,margin=1in,top=1.25in,bottom=1.25in}

% Graphics and figures
\\usepackage{graphicx}
\\usepackage{float}
\\usepackage{amssymb}
\\graphicspath{{../images/}}

% Index
