\\titleformat{\\chapter}[display]
  {\\normalfont\\huge\\bfseries}{\\chaptertitlename\\ \\thechapter}{20pt}{\\Huge}
\\titlespacing*{\\chapter}{0pt}{0pt}{40pt}

% Custom commands for figure sizing
\\newcommand{\\figheight}{0.5\\textheight}

