\\end{document}
EOF

    # Compile the standalone chapter
    compile_latex "build/${chapter_file}_standalone.tex" "${chapter_file}_standalone"
    
    # Move PDF to individual_pdfs directory
    if [ -f "build/${chapter_file}_standalone.pdf" ]; then
        cp "build/${chapter_file}_standalone.pdf" "build/individual_pdfs/${chapter_file}.pdf"
